import{_ as e,o as a,c as s,O as t}from"./chunks/framework.bdcb0ee1.js";const v=JSON.parse('{"title":"Private Messages","description":"","frontmatter":{},"headers":[],"relativePath":"userguide/private-messages.md","filePath":"userguide/private-messages.md","lastUpdated":1773167722000}'),o={name:"userguide/private-messages.md"},i=t('<h1 id="private-messages" tabindex="-1">Private Messages <a class="header-anchor" href="#private-messages" aria-label="Permalink to &quot;Private Messages&quot;">​</a></h1><p>Private messages let you have one-to-one conversations with other members away from the public forums.</p><nav class="table-of-contents"><ul><li><a href="#starting-a-conversation">Starting a conversation</a></li><li><a href="#sending-messages">Sending messages</a></li><li><a href="#viewing-your-conversations">Viewing your conversations</a></li><li><a href="#blocking">Blocking</a></li></ul></nav><h2 id="starting-a-conversation" tabindex="-1">Starting a conversation <a class="header-anchor" href="#starting-a-conversation" aria-label="Permalink to &quot;Starting a conversation&quot;">​</a></h2><p>To send a private message, visit a member&#39;s profile and click <strong>Message</strong>. If you have an existing conversation with that member, it will be opened. Otherwise, a new conversation is created.</p><img width="1942" height="471" alt="image" src="https://github.com/user-attachments/assets/61f3a38d-e792-432f-b396-7e3ecbdbaaad"><h2 id="sending-messages" tabindex="-1">Sending messages <a class="header-anchor" href="#sending-messages" aria-label="Permalink to &quot;Sending messages&quot;">​</a></h2><p>Type your message in the text box at the bottom of the conversation and click <strong>Send</strong>. Messages support BBCode formatting and must be between 5 and 5,000 characters.</p><h2 id="viewing-your-conversations" tabindex="-1">Viewing your conversations <a class="header-anchor" href="#viewing-your-conversations" aria-label="Permalink to &quot;Viewing your conversations&quot;">​</a></h2><p>Your conversations are listed in your message inbox, showing the other member&#39;s name and a preview of the most recent message. Unread conversations are highlighted.</p><p>Click on any conversation to view the full message history. Older messages are loaded automatically as you scroll up.</p><h2 id="blocking" tabindex="-1">Blocking <a class="header-anchor" href="#blocking" aria-label="Permalink to &quot;Blocking&quot;">​</a></h2><p>If you have blocked a user (or they have blocked you), you will not be able to send messages to each other.</p>',13),n=[i];function r(c,l,h,g,d,m){return a(),s("div",null,n)}const p=e(o,[["render",r]]);export{v as __pageData,p as default};
